mapper.select:
SELECT 
    r.id, r.requirement_no, r.title, r.org_id, r.dept_id, r.position_id,
    r.headcount, r.urgency_level, r.requirement_status, r.expected_entry_date,
    r.reason, r.industry_type, r.ext_json, r.remark, r.created_time, r.updated_time,
    o.name as orgName, d.name as deptName, p.name as positionName
FROM hr_recruit_requirement r
LEFT JOIN hr_organization o ON r.org_id = o.id
LEFT JOIN hr_department d ON r.dept_id = d.id
LEFT JOIN hr_position p ON r.position_id = p.id
WHERE r.deleted = 0

    AND r.title LIKE CONCAT('%', #{query.title}, '%')


    AND r.org_id = #{query.orgId}


    AND r.dept_id = #{query.deptId}


    AND r.position_id = #{query.positionId}


    AND r.requirement_status = #{query.requirementStatus}


    AND r.urgency_level = #{query.urgencyLevel}


    AND r.industry_type = #{query.industryType}


    AND r.expected_entry_date = #{query.expectedEntryDate}

ORDER BY r.created_time DESC
